/**
 * Serves the generated Capsule-Pro OpenAPI spec.
 *
 * GET /api-docs/openapi.json
 *
 * This is the machine-readable surface that the Scalar docs UI (app/api-docs/route.ts)
 * renders, and that any OpenAPI-aware tool/agent can consume. Like the docs page it
 * requires an authenticated session — the spec is not public. (Agents that only need
 * search can use the @repo/mcp-server openapi tools, which read the spec from disk.)
 *
 * The spec is generated by `pnpm manifest:openapi` into the monorepo-root
 * `manifest/api-docs/openapi.json` (outside this app); next.config.ts traces it into
 * the deployment via outputFileTracingIncludes.
 */
import { existsSync, readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { requireCurrentUser } from "@/app/lib/tenant";

export const dynamic = "force-dynamic";

const SPEC_REL = "manifest/api-docs/openapi.json";

/** Walk up from `start` until a directory containing pnpm-workspace.yaml is found. */
function findRepoRoot(start: string): string | null {
  let dir = start;
  for (;;) {
    if (existsSync(join(dir, "pnpm-workspace.yaml"))) {
      return dir;
    }
    const parent = dirname(dir);
    if (parent === dir) {
      return null;
    }
    dir = parent;
  }
}

/** Resolve the on-disk spec path across dev (cwd=apps/api) and traced deployments. */
function resolveSpecPath(): string | null {
  const cwd = process.cwd();
  const repoRoot = findRepoRoot(cwd);
  const candidates = [
    join(cwd, SPEC_REL), // cwd is the monorepo root (e.g. turbo run)
    join(cwd, "..", "..", SPEC_REL), // cwd is apps/api (next dev / traced lambda)
    ...(repoRoot ? [join(repoRoot, SPEC_REL)] : []),
  ];
  return candidates.find((p) => existsSync(p)) ?? null;
}

let cachedSpec: string | null = null;

export async function GET(): Promise<Response> {
  // ── Auth ──────────────────────────────────────────────────────
  try {
    await requireCurrentUser();
  } catch {
    return Response.json({ error: "Authentication required" }, { status: 401 });
  }

  // ── Read + cache the spec ─────────────────────────────────────
  if (!cachedSpec) {
    const specPath = resolveSpecPath();
    if (!specPath) {
      return Response.json(
        {
          error:
            "OpenAPI spec not found. Run `pnpm manifest:openapi` to generate it.",
        },
        { status: 404 }
      );
    }
    try {
      cachedSpec = readFileSync(specPath, "utf8");
    } catch (err) {
      return Response.json(
        {
          error: `Failed to read OpenAPI spec: ${
            err instanceof Error ? err.message : "unknown error"
          }`,
        },
        { status: 500 }
      );
    }
  }

  return new Response(cachedSpec, {
    status: 200,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      // Spec only changes on deploy (regenerated + committed); safe to cache.
      "Cache-Control": "public, max-age=300, stale-while-revalidate=86400",
    },
  });
}
